const item = $input.first().json;
const runId = item.runId;
const sections = item.sections || [];

console.log(`[SUB_Render_DOCX][${runId}] Preparing DOCX for ${sections.length} sections...`);

// In production: use docxtemplater, pandoc, or a DOCX generation API
// This sub-workflow represents the integration point for your DOCX renderer

// Option A: Call a self-hosted pandoc service
// Option B: Call AWS Lambda with docxtemplater
// Option C: Use n8n's HTTP node to call a DOCX API (e.g., DocRaptor, CloudConvert)

// The assembled markdown is passed through for the HTTP call
return [{
  json: {
    runId,
    markdownContent: item.assembledDraft || item.markdownContent || '',
    sectionCount: sections.length,
    renderService: process.env.DOCX_RENDER_URL || 'http://localhost:3002/render/docx',
    templateName: item.templateName || 'consultant_os_brd_template',
    metadata: {
      title: 'Business Requirements Document',
      author: 'Consultant OS',
      runId
    }
  }
}];

const runId = $('Prepare DOCX Structure').first().json.runId;
const response = $input.first().json || {};

// Render service should return a signed URL for the generated DOCX
const docxUrl = response.url || response.docxUrl || response.fileUrl ||
  `${process.env.STORAGE_BASE_URL || 'https://storage.consultant-os.com'}/runs/${runId}/exports/brd_document.docx`;

console.log(`[SUB_Render_DOCX][${runId}] DOCX ready: ${docxUrl}`);

return [{ json: { runId, docxUrl, renderSuccess: !!response.url } }];
